    r'^https?://(192\.168\.\d{1,3}\.\d{1,3}|10\.\d{1,3}\.\d{1,3}\.\d{1,3}|172\.(1[6-9]|2\d|3[01])\.\d{1,3}\.\d{1,3})(:\d+)?(/.*)?$',
  );

  static bool isValidLocalDeviceUrl(String url) {
    return _privateIpPattern.hasMatch(url);
  }

  static void assertValidLocalDeviceUrl(String url) {
    if (!isValidLocalDeviceUrl(url)) {
      throw ApiException(
        'Invalid local device URL. Only private network IPs are allowed: $url',
      );
    }
  }
}

