  Map<String, dynamic> _handleResponse(http.Response response) {
    final statusCode = response.statusCode;
    final body = response.body;

    if (statusCode >= 200 && statusCode < 300) {
      if (body.isEmpty) {
        return {'status': 'success', 'statusCode': statusCode};
      }

      try {
        final decoded = jsonDecode(body);
        if (decoded is Map<String, dynamic>) {
          return decoded;
        }
        // Wrap non-map responses
        return {'data': decoded, 'statusCode': statusCode};
      } on FormatException {
        return {'data': body, 'statusCode': statusCode};
      }
    }

    // Handle error responses
    String errorMessage;
    switch (statusCode) {
      case 400:
        errorMessage = 'Bad request';
        break;
      case 401:
        errorMessage = 'Unauthorized - authentication required';
        break;
      case 403:
        errorMessage = 'Forbidden - insufficient permissions';
        break;
      case 404:
        errorMessage = 'Resource not found';
        break;
      case 408:
        errorMessage = 'Request timeout';
        break;
      case 429:
        errorMessage = 'Too many requests - rate limited';
        break;
      case 500:
        errorMessage = 'Internal server error';
        break;
      case 502:
        errorMessage = 'Bad gateway';
        break;
      case 503:
        errorMessage = 'Service unavailable';
        break;
      default:
        errorMessage = 'HTTP error';
    }

    // Try to extract error details from response body
    try {
      final errorBody = jsonDecode(body);
      if (errorBody is Map<String, dynamic>) {
        final serverMessage = errorBody['message'] ??
            errorBody['error'] ??
            errorBody['detail'];
        if (serverMessage != null) {
          errorMessage = '$errorMessage: $serverMessage';
        }
      }
    } catch (_) {
      // Response body is not JSON, use default message
