/// Retry wrapper for transient failures
class RetryHttpService {
  final HttpService _httpService;
  final int maxRetries;
  final Duration retryDelay;

  RetryHttpService(
    this._httpService, {
    this.maxRetries = 3,
    this.retryDelay = const Duration(seconds: 1),
  });

  Future<Map<String, dynamic>> withRetry(
    Future<Map<String, dynamic>> Function() request, {
    int? retries,
  }) async {
    final maxAttempts = retries ?? maxRetries;
    ApiException? lastApiException;
    NetworkException? lastNetworkException;

    for (int attempt = 0; attempt <= maxAttempts; attempt++) {
      try {
        return await request();
      } on NetworkException catch (e) {
        lastNetworkException = e;
        if (attempt < maxAttempts) {
          await Future.delayed(retryDelay * (attempt + 1));
        }
      } on ApiException catch (e) {
        lastApiException = e;
        // Only retry on server errors (5xx) and rate limiting (429)
        if (e.statusCode != null &&
            (e.statusCode! >= 500 || e.statusCode == 429)) {
          if (attempt < maxAttempts) {
            await Future.delayed(retryDelay * (attempt + 1));
          }
        } else {
          // Don't retry client errors
          rethrow;
        }
      }
    }

    if (lastApiException != null) throw lastApiException;
    if (lastNetworkException != null) throw lastNetworkException;
    throw NetworkException('All retry attempts failed');
  }

  HttpService get httpService => _httpService;

  void dispose() {
    _httpService.dispose();
  }
}

