  );

  // Wrap with retry logic
  final retryService = RetryHttpService(
    httpService,
    maxRetries: 3,
    retryDelay: const Duration(seconds: 1),
  );

  try {
    // Cloud API example
    final cloudResponse = await retryService.withRetry(
      () => httpService.cloudGet('/api/v1/devices'),
    );
    print('Cloud devices: $cloudResponse');

    // Local IoT device example
    final deviceResponse = await retryService.withRetry(
      () => httpService.deviceGet(
        'http://192.168.1.100',
        '/api/status',
      ),
    );
    print('Device status: $deviceResponse');

    // Post command to local device
    final commandResponse = await httpService.devicePost(
      'http://192.168.1.100',
      '/api/command',
      body: {
        'action': 'toggle',
        'target': 'light_1',
      },
    );
    print('Command response: $commandResponse');

    // Check cloud health
    final cloudHealthy = await httpService.isCloudAvailable();
    print('Cloud API healthy: $cloudHealthy');

    // Check device health
    final deviceHealthy =
        await httpService.isDeviceAvailable('http://192.168.1.100');
    print('Device healthy: $deviceHealthy');

    // Discover devices on local network
    final devices = await httpService.discoverLocalDevices(
      subnet: '192.168.1',
      port: 80,
      timeout: const Duration(seconds: 2),
    );
    print('Discovered devices: $devices');
  } on ApiException catch (e) {
    print('API Error: ${e.message} (Status: ${e.statusCode})');
  } on NetworkException catch (e) {
    print('Network Error: ${e.message}');
  } finally {
    retryService.dispose();
  }
}